#include <stdio.h>
int main() {
    int T, N;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &N);
        if (N == 4) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

